var numIdenticalPairs = function(nums) {
    const counts = new Map();
    for (const v of nums) counts.set(v, (counts.get(v) || 0) + 1);
    let total = 0;
    for (const c of counts.values()) total += (c * (c - 1)) / 2;
    return total;
};
